  ('dietitian-moex-04407', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '長期高量葡萄糖或果糖攝取，會導致肝臟何種脂質的堆積，造成非酒精性脂肪肝的生成？', '["蠟脂", "磷脂質", "三酸甘油酯", "肌醇三磷酸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04408', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '酮體於肝臟合成後，會透過血液循環送至肝外組織，血液中的酮體主要型態為何？', '["乙醯輔酶A（acetyl-CoA）", "乙醯乙酸（acetoacetate）", "β-羥基丁酸（β-hydroxybutyric acid）", "β-羥甲基丁酸（β-hydroxymethylbutyric acid）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04409', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於神經磷脂質（sphingolipid）的敘述，下列何者錯誤？', '["神經磷脂質結構組成是以甘油作為骨架", "存在於腦部組織中，為構成神經細胞膜的主要成分", "結構碳骨架上接有脂肪酸", "腦磷脂（ceramide）與神經節糖苷（ganglioside）都是屬於神經磷脂質類別"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04410', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列那一個apolipoprotein發生突變，將造成細胞無法獲取（uptake）低密度脂蛋白，導致高膽固醇血症？', '["apolipoprotein A-1", "apolipoprotein B-48", "apolipoprotein B-100", "apolipoprotein E"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04411', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於血紅素（hemoglobin）的敘述，下列何者正確？', '["運送氧氣的重要蛋白質分子，不論原核或是真核生物體內都存在", "高等脊椎動物體內的血紅素，由四個次單元（tetrameric α2β2）組合而成", "血紅素分子表面有兩個可以結合氧氣分子的位置", "紅血球中含有2,3-bisphosphoglycerate（2,3-BPG）參與血紅素與氧分子結合的親和性，登山時體內的 2,3-BPG會降低，以提高氧分子的使用效率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04412', 'dietitian', 'dietitian-moex-113-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '關於肌酸（creatine）的敘述，下列何者正確？', '["來自於肉類及魚類食物，是身體可以自行合成的一種蛋白質，主要功能為參與能量代謝", "大約95%的肌酸儲存在肝臟中", "心臟受傷時可促使心肌細胞釋放肌酸激酶（creatine kinase），以增加肌酸的生成，有助於心臟的自我修 護", "肌酸被作為運動員的運動增補劑，被認為可促進肌肉能量代謝"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:35+00:00", "source_pdf_sha1": "67543ae9d102", "answer_pdf_sha1": "59e7cd37c769", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
